local LxUtf8 = LXFW.LxUtf8

local LWordMaskTrie = LXImport(".LWordMaskTrie")

---@class LWordMaskUtil
local LWordMaskUtil = LxClass("LWordMaskUtil", nil)
LWordMaskUtil.INVALID_ARR_CHARINPUT={ "%","\n",  "&", "*","\'", "\\", "\"", "~", "!", "$", "-", "+", "<", ">", "(", ")", ".", ",", "`", "?", ":", "/", "|", "^", "_", "=", "’"}
LWordMaskUtil.INVALID_ARR_CHAR = { "%"," ", "@", "&", "*","\'", "\\", "\"", "~", "!", "$", "-", "+", "[", "]", "{", "}", "<", ">", "(", ")", ".", ",", "`", "?", ":", "/", "|", "^", "_"}
LWordMaskUtil.INVALID_ARR_ENUS = { "[", "]","%", "|","="}

LWordMaskUtil.NAME_MAXLENGTH = 12 -- 名字最长长度
LWordMaskUtil.NAME_MINLENGTH = 1-- 名字最小长度

LWordMaskUtil.CHAT_MAXLENGTH = 16 -- 聊天字符串最大长度

LWordMaskUtil.INVALID_TYPE_NONE = 0 --有效
LWordMaskUtil.INVALID_TYPE_MAXLENGTH = 1 --长度超出最大限制
LWordMaskUtil.INVALID_TYPE_MINLENGTH = 2 --长度超出最小限制
LWordMaskUtil.INVALID_TYPE_FORBIDDENCHAR = 3 --无效字符
LWordMaskUtil.INVALID_TYPE_EMPTY = 4 --空字符串
LWordMaskUtil.INVALID_TYPE_MAXCHATLENGTH = 5 --超过聊天最大长度字符

LWordMaskUtil.PlaceWords = {} --替换字符串缓存

---@type LWordMaskTrie
LWordMaskUtil.trie = nil

function LWordMaskUtil.AutoLoad()
	if not LWordMaskUtil.IsNeedInit() then
		return
	end

	if LOG_INFO_ENABLED then
		printInfo("LWordMaskUtil", "---->>> InitTrie start ...")
	end
	
	LWordMaskUtil.InitTrie()
	local timer
	timer = MgrCenter.TimerMgr:NewTimeTimer(function()
		if not LWordMaskUtil.FrameAddTrieFromTable() then

			MgrCenter.TimerMgr:RemoveTimer(timer)

			if LOG_INFO_ENABLED then
				printInfo("LWordMaskUtil", "---->>> InitTrie end ...")
			end
		end
	 end, nil, 0, -1)
end

function LWordMaskUtil.InitTrie()
	if CS.IsWebGL() then
		return
	end
	if LGameSettings.platformSpecial == 1 then
		LWordMaskUtil.isSkipMask = true
		return
	end

	local trie = LWordMaskUtil.trie
	if not trie then
		trie = LWordMaskTrie:New()
		LWordMaskUtil.trie = trie
	end
	trie:InitTrie()
	LWordMaskUtil.AddTrie(gLGameLogin and gLGameLogin:GetMaskWebData())
end

function LWordMaskUtil.FrameAddTrieFromTable()
	local trie = LWordMaskUtil.trie
	if not trie then return false end
	return trie:FrameAddTrieFromTable()
end

function LWordMaskUtil.AddTrie(wordList)
	if not wordList then return end
	if #wordList == 0 then return end
	local trie = LWordMaskUtil.trie
	if not trie then return end
	trie:AddWebWordList(wordList)
end

function LWordMaskUtil.IsNeedInit()
	if CS.IsWebGL() then return false end

	if LGameSettings.platformSpecial == 1 then return false end

	local trie = LWordMaskUtil.trie
	if not trie then return true end

	return trie:IsNeedInit()
end

function LWordMaskUtil.ClearTrie()
	LWordMaskUtil.trie = nil
end

