function LWordMaskUtil.ClearShieldWord(strContent,isSign,tips,isChat)
	local isMatched,newText = LWordMaskUtil.ClearShieldWordInter(strContent,isSign,isChat,nil)
	if isMatched and tips then
		GF.ShowMessage(tips)
	end

	return newText, not isMatched
end

function LWordMaskUtil.ClearShieldWordEx(content,isSign,isChat,sceneType,func)
	if CS.IsWebGL() and LWxHelper.IsMiniGamePlatform() then
		if gLSdkImpl:CallMethod(LSdkMethod.IsWxMsgChecking) then
			gLGameWordMask:CheckStringMaskWx(content,sceneType,function (retCode,retText)
				if func then
					func(retCode ~= 0, retText)
				end
			end)
		else
			if func then
				func(false, content)
			end
		end
		return
	end

	gLGameWordMask:CheckStringMask(content,sceneType,function (retCode,retText)
		LWordMaskUtil.ClearShieldWordInter(retText,isSign,isChat,func)

	end)
end

function LWordMaskUtil.ClearShieldWordInter(content,isSign,isChat,func)
	local trie = LWordMaskUtil.trie
	if not trie then
		if func then
			func(false, content)
		end
		return false, content
	end
	local replace = true
	local charsType = 0
	local isInnerRegion = not gLGameLanguage:IsOtherLngRegion()
	if not isSign then
		if not isInnerRegion then
			charsType = 3
		elseif isChat then
			charsType = 1
		else
			charsType = 2
		end
	end
	local retCode,newText,oldStr = trie:FilterWord(content, nil, replace, charsType, nil)
	local bHaveMask = not (retCode == 0)
	if func then
		func(bHaveMask, newText)
	end
	return bHaveMask, newText

	--[[
