	local srclen = LxUtf8.len(_strWord)
	if srclen <= 0 then
		if func then
			func(false,_strWord)
		end
		return false,_strWord
	end
	local bHaveMask = false
	local _tmp

	local isChinese = not gLGameLanguage:IsForeignRegion()
	local isInnerRegion = not gLGameLanguage:IsOtherLngRegion()

	if isChinese then
		bHaveMask,_strWord,_tmp = LWordMaskUtil.DoCheckKeyWord(_strWord, true)
	else
		local tempStr = string.format(" %s ",_strWord)
		bHaveMask,_strWord,_tmp = LWordMaskUtil.DoCheckKeyWord(tempStr, true)
		local len = string.len(_strWord)
		_strWord = string.sub(_strWord,2,len-1)
	end


	if not isSign then
		local generatePlaceFunc = LWordMaskUtil.GeneratePlaceWord
		local list = {}

		if isChat then
			if isInnerRegion then
				list = LWordMaskUtil.INVALID_ARR_CHARINPUT
			else
				list = LWordMaskUtil.INVALID_ARR_ENUS
			end
		else
			if isInnerRegion then
				list = LWordMaskUtil.INVALID_ARR_CHAR
			else
				list = LWordMaskUtil.INVALID_ARR_ENUS
			end
		end
		for _, v in ipairs(list) do
			local lenWord = LxUtf8.len(v)
			if srclen >= lenWord then
				local a, b = string.find(_strWord,"%".. v)
				if a then
					bHaveMask = true
					local rePlaceWord = generatePlaceFunc(lenWord)
					_strWord = string.gsub(_strWord, "%"..v, rePlaceWord)
				end
			end
		end
	end

	if func then
		func(bHaveMask,_strWord)
	end

	return bHaveMask,_strWord
	]]
end

------------------------------------------------------------------
---屏蔽词的替换字符串
---根据长度构建不同长度的
------------------------------------------------------------------
function LWordMaskUtil.GeneratePlaceWord(lenWord)
	local placeWords = LWordMaskUtil.PlaceWords
	local word = placeWords[lenWord]
	if not word then
		word = string.rep("*", lenWord)
		placeWords[lenWord] = word
	end
	return word
end


